1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = {
9	  customer: Customer;
10	  steps: Step[];
11	};
12	type QuoteResult = { premium: number };
13	type ClaimResult = { payout: number; remainingCap: number };
14	type StepResult = QuoteResult | ClaimResult;
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
18	const CURSE_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS = 2;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	const BLOCK_SIZE = 3;
25	const BLOCK_BASE_PREMIUM = 60;
26	
27	const BASE_PREMIUMS: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  rune: 25,
33	  moonstone: 25,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const countByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	const componentsBase = (components: Item[]): number => {
47	  let total = 0;
48	  for (const [type, count] of countByType(components)) {
49	    total += count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
50	  }
51	  return total;
52	};
53	
54	const mainItemsBase = (items: Item[]): number =>
55	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
56	
57	const itemSurcharges = (item: Item): number => {
58	  const base = BASE_PREMIUMS[item.type];
59	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const highEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE_RATE : 0;
61	  return curse + highEnchant;
62	};
63	
64	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): QuoteResult => {
65	  const mainItems = step.items.filter((i) => !COMPONENT_TYPES.has(i.type));
66	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
67	
68	  const policyBase = mainItemsBase(mainItems) + componentsBase(components);
69	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
70	  const surcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
71	  const loyalty = customer.yearsWithMHPCO >= LOYALTY_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
72	  const followUp = isFollowUp ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
73	
74	  return { premium: Math.ceil(policyBase + firstInsurance + surcharges - loyalty - followUp + PROCESSING_FEE) };
75	};
76	
77	const DEDUCTIBLE = 100;
78	const CAP_MULTIPLIER = 2;
79	
80	const INSURANCE_VALUES: Record<string, number> = {
81	  sword: 1000,
82	  amulet: 600,
83	  staff: 800,
84	  potion: 400,
85	  rune: 250,
86	  moonstone: 250,
87	};
88	
89	const insuranceSum = (items: Item[]): number =>
90	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
91	
92	const HIGH_ENCHANT_PAYOUT_THRESHOLD = 8;
93	const HIGH_ENCHANT_PAYOUT_RATE = 0.5;
94	
95	const reimbursementRate = (item: Item | undefined): number =>
96	  (item?.enchantment ?? 0) >= HIGH_ENCHANT_PAYOUT_THRESHOLD ? HIGH_ENCHANT_PAYOUT_RATE : 1;
97	
98	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
99	  const item = policyItems.find((i) => i.type === damage.itemType);
100	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
101	};
102	
103	const claimResult = (step: ClaimStep, policyItems: Item[], availableCap: number): ClaimResult => {
104	  const rawPayout = step.incident.damages.reduce(
105	    (sum, d) => sum + damagePayout(d, policyItems),
106	    0,
107	  );
108	  const cappedPayout = Math.min(rawPayout, availableCap);
109	  const payout = Math.floor(cappedPayout);
110	  return { payout, remainingCap: availableCap - payout };
111	};
112	
113	const policyItemsFor = (step: ClaimStep, steps: Step[]): Item[] => {
114	  const policyStep = steps[step.policy];
115	  if (policyStep.op !== "quote") {
116	    throw new Error(`step ${step.policy} is not a quote`);
117	  }
118	  return policyStep.items;
119	};
120	
121	const initialCap = (policyItems: Item[]): number =>
122	  insuranceSum(policyItems) * CAP_MULTIPLIER;
123	
124	const processClaim = (
125	  step: ClaimStep,
126	  scenario: Scenario,
127	  remainingCapByPolicy: Map<number, number>,
128	): ClaimResult => {
129	  const policyItems = policyItemsFor(step, scenario.steps);
130	  const availableCap = remainingCapByPolicy.get(step.policy) ?? initialCap(policyItems);
131	  const result = claimResult(step, policyItems, availableCap);
132	  remainingCapByPolicy.set(step.policy, result.remainingCap);
133	  return result;
134	};
135	
136	export const run = (scenario: Scenario): { results: StepResult[] } => {
137	  const remainingCapByPolicy = new Map<number, number>();
138	  let quoteSeen = false;
139	  return {
140	    results: scenario.steps.map((step) => {
141	      if (step.op === "quote") {
142	        const result = quotePremium(step, scenario.customer, quoteSeen);
143	        quoteSeen = true;
144	        return result;
145	      }
146	      return processClaim(step, scenario, remainingCapByPolicy);
147	    }),
148	  };
149	};
